import{_ as t,c as a,o as r,ai as o}from"./chunks/framework.Cii4G981.js";const c=JSON.parse('{"title":"Join","description":"","frontmatter":{"sidebar":false,"aside":false,"docFooter":{"prev":false,"next":false}},"headers":[],"relativePath":"join.md","filePath":"join.md"}'),n={name:"join.md"};function i(d,e,s,h,l,p){return r(),a("div",null,e[0]||(e[0]=[o('<h1 id="join" tabindex="-1">Join <a class="header-anchor" href="#join" aria-label="Permalink to &quot;Join&quot;">​</a></h1><p>We are a community of cloud technology enthusiasts and welcome new members at any scale.</p><p>For the exact conditions and benefits available to members read through <a href="https://cdn.platform.linuxfoundation.org/agreements/neonephos-foundation.pdf?__hstc=81619592.11739e1f4ca03192f4e918409f725053.1748961872693.1753863796744.1753964512976.20&amp;__hssc=81619592.3.1753964512976&amp;__hsfp=2164450451" target="_blank" rel="noreferrer">our charter</a>.</p><h2 id="membership-tiers" tabindex="-1">Membership Tiers <a class="header-anchor" href="#membership-tiers" aria-label="Permalink to &quot;Membership Tiers&quot;">​</a></h2><p>We have three membership tiers available - Premier, General and Associate memberships.</p><table tabindex="0"><thead><tr><th>Premier</th><th>General</th><th>Associate</th></tr></thead><tbody><tr><td><a href="#premier-member-fee-scale">50k € p.a. - 100k € p.a.</a></td><td><a href="#general-member-fee-scale">5k € p.a. - 50k € p.a.</a></td><td>free</td></tr><tr><td>Voting Governing Board Seat</td><td><a href="#shared-general-governing-board-representative">Shared Voting Governing Board Seat</a></td><td>Observer Status in Governing Board</td></tr><tr><td>Voting Technical Advisory Council Seat</td><td>Observer Status in Technical Advisory Council</td><td>Observer Status in Technical Advisory Council</td></tr></tbody></table><h2 id="premier-member-fee-scale" tabindex="-1">Premier Member Fee Scale <a class="header-anchor" href="#premier-member-fee-scale" aria-label="Permalink to &quot;Premier Member Fee Scale&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Consolidated Employees</th><th>Fee</th></tr></thead><tbody><tr><td>up to 200</td><td>75k € p.a.</td></tr><tr><td>more than 200</td><td>100k € p.a.</td></tr></tbody></table><h2 id="general-member-fee-scale" tabindex="-1">General Member Fee Scale <a class="header-anchor" href="#general-member-fee-scale" aria-label="Permalink to &quot;General Member Fee Scale&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Consolidated Employees</th><th>Fee</th></tr></thead><tbody><tr><td>under 100</td><td>5k € p.a.</td></tr><tr><td>up to 499</td><td>10k € p.a.</td></tr><tr><td>up to 4999</td><td>30k € p.a.</td></tr><tr><td>more than 5000</td><td>50k € p.a.</td></tr></tbody></table><h2 id="shared-general-governing-board-representative" tabindex="-1">Shared General Governing Board Representative <a class="header-anchor" href="#shared-general-governing-board-representative" aria-label="Permalink to &quot;Shared General Governing Board Representative&quot;">​</a></h2><p>One voting representative for every 5 General Members.</p><h2 id="applying-for-membership" tabindex="-1">Applying For Membership <a class="header-anchor" href="#applying-for-membership" aria-label="Permalink to &quot;Applying For Membership&quot;">​</a></h2><p><a href="https://enrollment.lfx.linuxfoundation.org/?project=neonephos-foundation&amp;__hstc=81619592.11739e1f4ca03192f4e918409f725053.1748961872693.1753863796744.1753964512976.20&amp;__hssc=81619592.2.1753964512976&amp;__hsfp=2164450451" target="_blank" rel="noreferrer">Start the process here.</a></p><p>If you have questions do not hesitate to contact <a href="mailto:formation@neonephos.org" target="_blank" rel="noreferrer">formation@neonephos.org</a>.</p>',15)]))}const b=t(n,[["render",i]]);export{c as __pageData,b as default};
